function safeParse(value, fallback) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function str(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value);
}

function nullableStr(value) {
  if (value === null || value === undefined || value === '') return '';
  return String(value);
}

function bool(value, fallback = false) {
  if (value === null || value === undefined || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  return Number(value) === 1;
}

function inferProximaAcao(row) {
  const status = str(row.status_lead, '');
  const statusPagamento = str(row.status_pagamento, '');
  const guiaEnviado = bool(row.guia_enviado, false);
  const comprovanteRecebido = bool(row.comprovante_recebido, false);
  const deveRepassarHumano = bool(row.deve_repassar_humano, false);
  const preReservaCriada = bool(row.pre_reserva_criada, false);
  const encerrado = bool(row.encerrado, false);

  if (encerrado || status.startsWith('ENCERRADO')) return 'ENCERRAR_CONVERSA';
  if (deveRepassarHumano || status === 'TRANSFERIDO_FLAVIA') return 'REPASSAR_HUMANO';
  if (preReservaCriada || status === 'PRE_RESERVA_CRIADA') return 'CONFIRMAR_PRE_RESERVA';
  if (status === 'AGUARDANDO_ESCOLHA_HORARIO') return 'ENVIAR_OU_CONFIRMAR_HORARIOS';
  if (comprovanteRecebido || status === 'COMPROVANTE_RECEBIDO') return 'VALIDAR_COMPROVANTE';
  if (status === 'AGUARDANDO_PAGAMENTO' || statusPagamento === 'aguardando_pagamento') return 'SOLICITAR_PAGAMENTO';
  if (status === 'APTO_PARA_AVALIACAO' && !guiaEnviado) return 'ENVIAR_GUIA';
  if (status === 'APTO_PARA_AVALIACAO' && guiaEnviado) return 'SOLICITAR_PAGAMENTO';
  if (status === 'PRE_REPROVADO') return 'EXPLICAR_PRE_REPROVACAO';
  if (status === 'NOVO_LEAD' || status === 'COLETANDO_DADOS' || status === 'QUALIFICANDO') return 'PEDIR_DADOS_CAO';

  return '';
}

function inferObservacoesResumoLead(row) {
  return nullableStr(
    row.observacoes ||
    row.motivo_pre_reprovacao ||
    row.motivo_repasse ||
    ''
  );
}

function inferObservacoesRepasse(row) {
  return nullableStr(
    row.observacoes_internas ||
    row.motivo_repasse ||
    row.motivo_pre_reprovacao ||
    ''
  );
}

return $input.all().map((item) => {
  const row = Array.isArray(item.json) ? (item.json[0] || {}) : (item.json || {});

  const resumoLeadJson = safeParse(row.resumo_lead_json, {});
  const resumoRepasseJson = safeParse(row.resumo_interno_repasse_json, {});

  const telefone = row.telefone_e164 || row.phone || '';
  const proximaAcao = inferProximaAcao(row);

  const deveRepassarHumano = bool(row.deve_repassar_humano, false);
  const comprovanteRecebido = bool(row.comprovante_recebido, false);
  const guiaEnviado = bool(row.guia_enviado, false);
  const preReservaCriada = bool(row.pre_reserva_criada, false);
  const encerrado = bool(row.encerrado, false);

  const inputs = {
    status_lead: str(row.status_lead, 'NOVO_LEAD'),
    ultima_intencao: row.ultima_intencao ?? null,
    evento_sistema: row.evento_sistema_atual ?? row.evento_sistema ?? null,
    mensagens_resposta: [],

    resumo_lead: {
      tutor_nome: nullableStr(resumoLeadJson.tutor_nome || row.nome_tutor),
