  ];
}

const first = slots[0];
let second = null;

// 1. Procura slot com diferença mínima de 2h
second = slots.find((slot, index) => {
  if (index === 0) return false;
  return getMinutesDiff(first.starts_at, slot.starts_at) >= MIN_DIFF_MINUTES;
});

// 2. Se não achar, tenta slot no próximo turno
if (!second) {
  second = slots.find((slot, index) => {
    if (index === 0) return false;
    return slot.local_shift !== first.local_shift;
  });
}

// 3. Se ainda não achar, pega o próximo slot diferente do primeiro
if (!second) {
  second = slots.find((slot, index) => index > 0);
}

const offeredSlots = second ? [first, second] : [first];

return [
  {
    json: {
      success: true,
      timezone: TIMEZONE,
      rule: {
        first_option: 'slot mais próximo disponível',
        second_option: 'slot com diferença mínima de 4h; se não houver, próximo turno; se não houver, próximo slot disponível',
      },
      option_1: first
        ? {
            starts_at: first.starts_at,
            ends_at: first.ends_at,
            display: first.display,
            short_display: first.short_display,
            shift: first.local_shift,
          }
        : null,
      option_2: second
        ? {
            starts_at: second.starts_at,
            ends_at: second.ends_at,
            display: second.display,
            short_display: second.short_display,
            shift: second.local_shift,
          }
        : null,
      offered_slots: offeredSlots.map((slot, index) => ({
        option_id: `option_${index + 1}`,
        starts_at: slot.starts_at,
        ends_at: slot.ends_at,
        display: slot.display,
        short_display: slot.short_display,
        shift: slot.local_shift,
      })),
      whatsapp_message: second
        ? `Tenho dois horários a conversa com o especialista: \n*1. ${first.display}* ou \n*2. ${second.display}*. \nQual fica melhor para você?`
        : `Tenho somente um horário disponível para a conversa com nosso especialista: \n*1. ${first.display}*. \nEsse horário funciona para você?`,
    },
  },
];

const original = $('Devo responder?').first().json;
const currentMessageId = Number(original.current_message_id);

const root = $input.first().json;
const messages = Array.isArray(root.payload) ? root.payload : [];

// ordenar por id crescente
messages.sort((a, b) => Number(a.id) - Number(b.id));

// vamos pegar a sequência final de mensagens do lead
const grouped = [];

// encontrar o índice da mensagem atual
const currentIndex = messages.findIndex(m => Number(m.id) === currentMessageId);

if (currentIndex === -1) {
  return [
    {
      json: {
        merged_lead_message: original.message || '',
        grouped_message_ids: [currentMessageId]
      }
    }
  ];
}

// andar para trás a partir da mensagem atual
for (let i = currentIndex; i >= 0; i--) {
  const msg = messages[i];
  const type = Number(msg.message_type);

  if (type === 0) {
    grouped.unshift(msg); // incoming do lead
  } else {
    // se encontrou outgoing ou system antes do bloco atual, para
    if (grouped.length > 0) break;
  }
}

const mergedText = grouped
  .map(m => (m.content || '').trim())
  .filter(Boolean)
  .join('\n');

return [
  {
    json: {
      message: mergedText || original.message || '',
//      grouped_message_ids: grouped.map(m => m.id)
    }
  }
];

const timezone = "America/Sao_Paulo";

function safeString(v) {
  return v === undefined || v === null ? "" : String(v).trim();
}

function normalizeText(str) {
  return safeString(str)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

function encodeQueryValue(v) {
  return encodeURIComponent(safeString(v));
}

function getZonedDateParts(date, timeZone) {
  const formatter = new Intl.DateTimeFormat("en-CA", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    weekday: "short",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });

  const parts = formatter.formatToParts(date);
  const obj = {};
  for (const part of parts) {
    if (part.type !== "literal") obj[part.type] = part.value;
  }
  return obj;
}

function buildSafeBaseDate(timeZone) {
  const now = new Date();
  const parts = getZonedDateParts(now, timeZone);
  return new Date(`${parts.year}-${parts.month}-${parts.day}T12:00:00`);
}

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function formatISODate(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}`;
}

function formatBRDate(date) {
  const yyyy = date.getFullYear();
  const mm = String(date.getMonth() + 1).padStart(2, "0");
  const dd = String(date.getDate()).padStart(2, "0");
  return `${dd}/${mm}/${yyyy}`;
}

function isValidISODate(str) {
  return /^\d{4}-\d{2}-\d{2}$/.test(safeString(str));
}

const weekMap = {
  domingo: 0,
  segunda: 1,
  terca: 2,
  quarta: 3,
  quinta: 4,
  sexta: 5,
  sabado: 6,
};

const input = $json;

const requestedDayRaw = safeString(input.requested_day);
const requestedDateRaw = safeString(input.requested_date);
const senderName = safeString(input.sender_name);
const emailRaw = safeString(input.email).toLowerCase();

const baseDate = buildSafeBaseDate(timezone);

let requestedDate = null;
let scheduling_strategy = "";
let scheduling_reason = "";

// 1. Prioridade máxima: requested_date já preenchido
if (isValidISODate(requestedDateRaw)) {
  requestedDate = new Date(`${requestedDateRaw}T12:00:00`);
  scheduling_strategy = "requested_date";
  scheduling_reason = "Usou requested_date recebido da IA";
}

// 2. Segunda prioridade: requested_day
else if (requestedDayRaw) {
  const normalizedDay = normalizeText(requestedDayRaw);

  if (normalizedDay === "hoje") {
    requestedDate = baseDate;
    scheduling_strategy = "requested_day";
    scheduling_reason = "Usou requested_day = hoje";
  } else if (normalizedDay === "amanha" || normalizedDay === "amanhã") {
    requestedDate = addDays(baseDate, 1);
    scheduling_strategy = "requested_day";
    scheduling_reason = "Usou requested_day = amanhã";
  } else {
    const targetDay = weekMap[normalizedDay];

    if (targetDay !== undefined) {
      const currentDay = baseDate.getDay();
      let diff = (targetDay - currentDay + 7) % 7;

      if (diff === 0) diff = 7;

      requestedDate = addDays(baseDate, diff);
      scheduling_strategy = "requested_day";
      scheduling_reason = `Usou requested_day = ${requestedDayRaw}`;
    }
  }
}

// 3. Fallback automático: 48h pra frente
if (!requestedDate) {
  requestedDate = addDays(baseDate, 2);
  scheduling_strategy = "fallback_48h";
  scheduling_reason = "requested_day/requested_date ausentes ou inválidos. Aplicado fallback de 48h";
}

const requested_date_iso = formatISODate(requestedDate);
const requested_date_br = formatBRDate(requestedDate);

// Link de agendamento
const queryParts = [];

if (senderName) {
  queryParts.push(`name=${encodeQueryValue(senderName)}`);
}

if (emailRaw) {
  queryParts.push(`email=${encodeQueryValue(emailRaw)}`);
}

const bookingLinkBase = "https://agenda.convertix.app/r1";
const bookingLink = queryParts.length > 0
  ? `${bookingLinkBase}?${queryParts.join("&")}`
  : bookingLinkBase;

// Mensagem sugerida para o cliente
const bookingMessage =
  `Se quiser agilizar, você pode usar o link abaixo para escolher um horário de sua preferência, que fica mais rápido.\n` +
  `Link: ${bookingLink}`;

return [
  {
    json: {
      ...input,
      requested_date_iso,
      requested_date_br,
      scheduling_strategy,
      scheduling_reason,
      booking_link: bookingLink,
      booking_message: bookingMessage,
    },
  },
];

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

const baseItem = $('Hidrata Memória SQL').first().json;
const histItem = $json || {};

const output = {
  ...baseItem,

  message: {
    ...baseItem.message,
    content:
      histItem?.message?.content ||
      histItem?.message ||
      histItem?.last_user_message ||
      baseItem?.message?.content ||
      '',
    historico:
      histItem?.message?.historico ||
      histItem?.source ||
      'atual'
  },

  inputs: {
    ...(baseItem.inputs || {}),
    ...(histItem.inputs || {}),
    booking_link:
      (baseItem.inputs && baseItem.inputs.booking_link) ||
      'https://agenda.convertix.app/r1'
  }
};

return [{ json: removeEmpty(output) }];

function removeEmpty(value) {
  if (Array.isArray(value)) {
    return value
      .map(removeEmpty)
      .filter(v => v !== null && v !== undefined && v !== '');
  }

  if (value && typeof value === 'object') {
    const out = {};
    for (const [key, val] of Object.entries(value)) {
      const cleaned = removeEmpty(val);

      if (cleaned === null || cleaned === undefined || cleaned === '') continue;
      if (Array.isArray(cleaned) && cleaned.length === 0) continue;
      if (
        typeof cleaned === 'object' &&
        !Array.isArray(cleaned) &&
        Object.keys(cleaned).length === 0
      ) continue;

      out[key] = cleaned;
    }
    return out;
  }

  return value;
}

function parseJsonSafe(value) {
  if (!value) return value;
  if (typeof value === 'object') return value;

  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
}

const baseItem = $('Mensagem interpretada').first().json;
const memoryRaw = $('MEMORY').first()?.json.memory || {};

// LEAD
const hydratedLead = removeEmpty({
  ...baseItem.lead,
  sender_name: baseItem.lead?.sender_name || memoryRaw.name || '',
  phone: baseItem.lead?.phone || memoryRaw.phone || '',
  entry_channel: baseItem.lead?.entry_channel || memoryRaw.entry_channel || '',
  utms: baseItem.lead?.utms || parseJsonSafe(memoryRaw.utms) || {},
  sender_type: baseItem.lead?.sender_type || '',
  company_name: baseItem.lead?.company_name || memoryRaw.company_name || '',
  instagram: baseItem.lead?.instagram || memoryRaw.instagram || '',
  website: baseItem.lead?.website || memoryRaw.website || '',
  google_business_profile:
    baseItem.lead?.google_business_profile || memoryRaw.google_business_profile || ''
});

// CHATWOOT
const hydratedChatwoot = removeEmpty({
  ...baseItem.chatwoot,
  account_id: baseItem.chatwoot?.account_id || memoryRaw.account_id || '',
  contact_id: baseItem.chatwoot?.contact_id || memoryRaw.contact_id || '',
  conversation_id: baseItem.chatwoot?.conversation_id || memoryRaw.conversation_id || '',
  message_id: baseItem.chatwoot?.message_id || '',
  labels: baseItem.chatwoot?.labels || [],
  system_event: baseItem.chatwoot?.system_event || '',
  event: baseItem.chatwoot?.event || '',
  dify_uuid: baseItem.chatwoot?.dify_uuid || memoryRaw.dify_uuid || ''
});

// AGENDA separado
const agenda = removeEmpty({
  selected_option: baseItem.inputs?.agenda?.selected_option || memoryRaw.selected_option || '',
  selected_option_start: baseItem.inputs?.agenda?.selected_option_start || memoryRaw.selected_option_start || '',
  option_1_start: baseItem.inputs?.agenda?.option_1_start || memoryRaw.option_1_start || '',
  option_2_start: baseItem.inputs?.agenda?.option_2_start || memoryRaw.option_2_start || '',
  requested_day: baseItem.inputs?.agenda?.requested_day || memoryRaw.requested_day || '',
  requested_date: baseItem.inputs?.agenda?.requested_date || memoryRaw.requested_date || '',
  requested_period: baseItem.inputs?.agenda?.requested_period || memoryRaw.requested_period || '',
  requested_time_min: baseItem.inputs?.agenda?.requested_time_min || memoryRaw.requested_time_min || '',
  requested_time_max: baseItem.inputs?.agenda?.requested_time_max || memoryRaw.requested_time_max || '',
  email: baseItem.inputs?.agenda?.email || memoryRaw.email || '',
  agenda_reply_type: baseItem.inputs?.agenda?.agenda_reply_type || ''
});

// INPUTS
const hydratedInputs = removeEmpty({
  ...(baseItem.inputs || {}),

  lead_status: baseItem.inputs?.lead_status || memoryRaw.lead_status || '',
  last_intent: baseItem.inputs?.last_intent || memoryRaw.last_intent || '',
  previous_lead_status: memoryRaw.lead_status || '',
  previous_last_intent: memoryRaw.last_intent || '',
  lead_summary: baseItem.inputs?.lead_summary || parseJsonSafe(memoryRaw.lead_summary) || {},
  last_user_message: baseItem.inputs?.last_user_message || memoryRaw.last_user_message || '',
  last_ai_message: baseItem.inputs?.last_ai_message || memoryRaw.last_ai_message || '',
  memory_system_event: baseItem.inputs?.memory_system_event || memoryRaw.system_event || '',

  agenda
});

// SCORE separado
const score = removeEmpty({
  lead_score: memoryRaw.lead_score,
  lead_temperature: memoryRaw.lead_temperature,
  score_estrutura: memoryRaw.score_estrutura,
  score_potencial_comercial: memoryRaw.score_potencial_comercial,
  score_execucao: memoryRaw.score_execucao,
  score_investimento: memoryRaw.score_investimento,
  score_conversa: memoryRaw.score_conversa,
  score_bonus: memoryRaw.score_bonus,
  score_penalty: memoryRaw.score_penalty
});

const output = removeEmpty({
  ...baseItem,
  lead: hydratedLead,
  chatwoot: hydratedChatwoot,
  inputs: hydratedInputs,
  score
});

return [{ json: output }];

const msg = String(
  $json.inputs?.interpreted_message ||
  $json.message?.content ||
  $json.inputs?.last_user_message ||
  ''
).toLowerCase().trim();

const leadStatus = String($json.inputs?.lead_status || '');
const lastIntent = String($json.inputs?.last_intent || '');
const memorySystemEvent = String($json.inputs?.memory_system_event || '');

let agenda_reply_type = 'UNKNOWN';
let requested_day = '';
let requested_period = '';
let requested_time_min = '';
let requested_time_max = '';

const isAgendaFlow =
  [
    'AGUARDANDO_ESCOLHA_HORARIO',
    'SOLICITAR_NOVAS_OPCOES'
  ].includes(leadStatus) ||
  lastIntent === 'HORARIOS_ENVIADOS' ||
  memorySystemEvent === 'HORARIOS_ENVIADOS';

if (isAgendaFlow) {
  if (/(primeira opção|primeira opcao|opção 1|opcao 1|segunda opção|segunda opcao|opção 2|opcao 2)\b/i.test(msg)) {
    agenda_reply_type = 'OPTION_SELECTION';
  } else if (/(não tenho interesse|nao tenho interesse|não quero agendar|nao quero agendar|pode encerrar|não quero mais|nao quero mais)/i.test(msg)) {
    agenda_reply_type = 'REAL_MEETING_REJECTION';
  } else if (/^(não obrigado|nao obrigado|não|nao|deixa pra lá|deixa pra la)$/i.test(msg)) {
    agenda_reply_type = 'AMBIGUOUS_NEGATIVE';
  } else if (/(nenhum desses|nenhuma dessas|esses horários não|esses horarios nao|outro horário|outro horario|não consigo nesses|nao consigo nesses|pode ser outro|tem outro)/i.test(msg)) {
    agenda_reply_type = 'REJECTED_OPTIONS';
  } else if (/(segunda|terça|terca|quarta|quinta|sexta|sábado|sabado|domingo|\b\d{1,2}h\b|\b\d{1,2}:\d{2}\b|manhã|manha|tarde|noite)/i.test(msg)) {
    agenda_reply_type = 'NEW_TIME_REQUEST';
  }

  if (/segunda/.test(msg)) requested_day = 'segunda';
  if (/terça|terca/.test(msg)) requested_day = 'terça';
  if (/quarta/.test(msg)) requested_day = 'quarta';
  if (/quinta/.test(msg)) requested_day = 'quinta';
  if (/sexta/.test(msg)) requested_day = 'sexta';
  if (/sábado|sabado/.test(msg)) requested_day = 'sábado';
  if (/domingo/.test(msg)) requested_day = 'domingo';

  if (/manhã|manha/.test(msg)) requested_period = 'manha';
  if (/tarde/.test(msg)) requested_period = 'tarde';
  if (/noite/.test(msg)) requested_period = 'noite';

  const timeMatch = msg.match(/\b(\d{1,2})h(?:(\d{2}))?\b|\b(\d{1,2}):(\d{2})\b/);

  if (timeMatch) {
    const hh = timeMatch[1] || timeMatch[3];
    const mm = timeMatch[2] || timeMatch[4] || '00';
    requested_time_min = `${String(hh).padStart(2, '0')}:${String(mm).padStart(2, '0')}:00`;
    requested_time_max = requested_time_min;
  }
}

return [
  {
    json: {
      ...$json,
      inputs: {
        ...($json.inputs || {}),
        agenda: {
          ...($json.inputs?.agenda || {}),
          agenda_reply_type,
          requested_day,
          requested_period,
          requested_time_min,
          requested_time_max
        }
      }
    }
  }
];

